import sysfrom pathlib import Pathimport pandas as pdfrom datasets import load_dataset# Ensure project root is on sys.pathPROJECT_ROOT = Path(__file__).resolve().parents[1]if str(PROJECT_ROOT) not in sys.path:    sys.path.insert(0, str(PROJECT_ROOT))from config import INTERIM_DATA_DIRDATASET_NAME = "JanosAudran/financial-reports-sec"DATASET_CONFIG = "small_full"SPLITS = ["train", "validation", "test"]def add_section_name(df: pd.DataFrame, split_ds) -> pd.DataFrame:    """    Map numeric section IDs to human-readable section names.    """    if "section" not in df.columns:        raise ValueError("Column 'section' not found in dataframe.")    section_feature = split_ds.features["section"]    section_names = section_feature.names    id2name = {i: name for i, name in enumerate(section_names)}    df["section_name"] = df["section"].map(id2name)    return dfdef basic_checks(df: pd.DataFrame, split_name: str) -> None:    """    Print basic information and validate key columns.    """    expected_cols = {        "cik",        "sentence",        "section",        "labels",        "filingDate",        "docID",        "sentenceID",        "sentenceCount",    }    missing = expected_cols - set(df.columns)    if missing:        raise ValueError(f"[{split_name}] Missing expected columns: {missing}")    print(f"\n--- {split_name.upper()} BASIC INFO ---")    print(f"Shape: {df.shape}")    print("Columns:")    print(df.columns.tolist())    print("\nNull counts for key columns:")    print(df[["sentence", "docID", "labels", "filingDate"]].isna().sum())    print("\nSample rows:")    print(df.head(3))def save_split(df: pd.DataFrame, split_name: str) -> Path:    """    Save split dataframe to parquet in data/interim/.    """    out_path = INTERIM_DATA_DIR / f"{split_name}_sent_{DATASET_CONFIG}.parquet"    df.to_parquet(out_path, index=False)    return out_pathdef main():    INTERIM_DATA_DIR.mkdir(parents=True, exist_ok=True)    print(f"Loading dataset: {DATASET_NAME} | config: {DATASET_CONFIG}")    ds = load_dataset(DATASET_NAME, DATASET_CONFIG)    saved_paths = []    for split_name in SPLITS:        print(f"\n==============================")        print(f"Processing split: {split_name}")        print(f"==============================")        split_ds = ds[split_name]        print(f"Converting {split_name} to pandas DataFrame...")        df = split_ds.to_pandas()        print("Adding section_name...")        df = add_section_name(df, split_ds)        basic_checks(df, split_name)        print(f"Saving {split_name} split to parquet...")        out_path = save_split(df, split_name)        saved_paths.append(out_path)        print(f"Saved: {out_path}")    print("\nAll splits processed and saved successfully.")    print("\nSaved files:")    for p in saved_paths:        print(p)if __name__ == "__main__":    main()